<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('products.manage');$id=(int)vp3_input('id');
if(vp3_method()==='POST'){vp3_verify_csrf();$productId=vp3_input('product_id');$slug=vp3_input('slug');$name=vp3_input('name');$type=vp3_input('product_type');$status=vp3_input('status');if($name===''||$type===''||!preg_match('/^[A-Z0-9-]{6,100}$/',$productId)||!preg_match('/^[a-z0-9-]{3,190}$/',$slug)||!in_array($status,['draft','active','retired'],true)){vp3_flash('error','Product fields are invalid.');vp3_redirect('admin/product.php'.($id?'?id='.$id:''));}
 if($id){$stmt=vp3_db()->prepare('UPDATE products SET product_id=?,name=?,slug=?,description=?,product_type=?,current_version=?,status=?,self_hosted_enabled=?,hosted_enabled=?,updated_at=NOW() WHERE id=?');$stmt->execute([$productId,$name,$slug,vp3_input('description'),$type,vp3_input('current_version'),$status,isset($_POST['self_hosted_enabled'])?1:0,isset($_POST['hosted_enabled'])?1:0,$id]);$entity=(string)$id;}else{$stmt=vp3_db()->prepare('INSERT INTO products(product_id,name,slug,description,product_type,current_version,status,self_hosted_enabled,hosted_enabled,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,NOW(),NOW())');$stmt->execute([$productId,$name,$slug,vp3_input('description'),$type,vp3_input('current_version')?:null,$status,isset($_POST['self_hosted_enabled'])?1:0,isset($_POST['hosted_enabled'])?1:0]);$id=(int)vp3_db()->lastInsertId();$entity=(string)$id;}vp3_audit('admin',(int)$admin['id'],'product.saved','product',$entity,['product_id'=>$productId]);vp3_redirect('admin/product.php?id='.$id);}
$row=['product_id'=>'VP3-','name'=>'','slug'=>'','description'=>'','product_type'=>'media_platform','current_version'=>'','status'=>'draft','self_hosted_enabled'=>1,'hosted_enabled'=>1];if($id){$s=vp3_db()->prepare('SELECT * FROM products WHERE id=?');$s->execute([$id]);$found=$s->fetch();if(!is_array($found)){http_response_code(404);exit('Product not found.');}$row=$found;}$pageTitle=$id?'Edit Product':'New Product';require VP3_ROOT.'/includes/admin-header.php';?><h1><?=$id?'Edit':'Create'?> product</h1><form class="card" method="post"><?=vp3_csrf_field()?><div class="grid two"><div class="field"><label>Product ID</label><input name="product_id" value="<?=vp3_e($row['product_id'])?>" required pattern="[A-Z0-9-]{6,100}"></div><div class="field"><label>Name</label><input name="name" value="<?=vp3_e($row['name'])?>" required></div><div class="field"><label>Slug</label><input name="slug" value="<?=vp3_e($row['slug'])?>" required pattern="[a-z0-9-]{3,190}"></div><div class="field"><label>Product type</label><input name="product_type" value="<?=vp3_e($row['product_type'])?>" required></div><div class="field"><label>Current version</label><input name="current_version" value="<?=vp3_e($row['current_version'])?>"></div><div class="field"><label>Status</label><select name="status"><?php foreach(['draft','active','retired'] as $st):?><option <?=$row['status']===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select></div></div><div class="field"><label>Description</label><textarea name="description"><?=vp3_e($row['description'])?></textarea></div><label><input type="checkbox" name="self_hosted_enabled" <?=$row['self_hosted_enabled']?'checked':''?>> Self-hosted enabled</label> <label><input type="checkbox" name="hosted_enabled" <?=$row['hosted_enabled']?'checked':''?>> Hosted enabled</label><br><br><button class="button">Save product</button></form><?php require VP3_ROOT.'/includes/admin-footer.php';?>
